import{_ as o,c as d,o as t,ae as c}from"./chunks/framework.B7Y1jjX-.js";const a="/pressidian/assets/Pasted%20image%2020250908165423.DYpC66k3.png",m=JSON.parse('{"title":"基础","description":"","frontmatter":{},"headers":[],"relativePath":"generated-notes/前端/包管理工具/npm/npm.md","filePath":"generated-notes/前端/包管理工具/npm/npm.md"}'),n={name:"generated-notes/前端/包管理工具/npm/npm.md"};function l(r,e,s,i,p,g){return t(),d("div",null,[...e[0]||(e[0]=[c('<h1 id="基础" tabindex="-1">基础 <a class="header-anchor" href="#基础" aria-label="Permalink to &quot;基础&quot;">​</a></h1><hr><h5 id="npm依赖于node-js" tabindex="-1">npm依赖于Node.js <a class="header-anchor" href="#npm依赖于node-js" aria-label="Permalink to &quot;npm依赖于Node.js&quot;">​</a></h5><h1 id="常用命令" tabindex="-1">常用命令 <a class="header-anchor" href="#常用命令" aria-label="Permalink to &quot;常用命令&quot;">​</a></h1><hr><h5 id="锁文件" tabindex="-1">锁文件 <a class="header-anchor" href="#锁文件" aria-label="Permalink to &quot;锁文件&quot;">​</a></h5><ul><li><code>echo &#39;package-lock=false&#39; &amp;gt;&amp;gt; .npmrc</code>在包中禁用锁文件</li></ul><h5 id="下载与更新" tabindex="-1">下载与更新 <a class="header-anchor" href="#下载与更新" aria-label="Permalink to &quot;下载与更新&quot;">​</a></h5><p><code>npm install [包名]@[版本]</code> <code>-g</code> 在全局安装 <code>install</code>可以简写为<code>i</code><code>npm init -y</code>初始化项目 -y 或者--yes 是使用默认值，后期可以在package.json中修改 <code>npm uninstall [包名]</code>卸载 <code>npm update [包名]</code>更新</p><p>在npm中，包（package）、模块（module）、依赖（dependency）说的都是一回事儿。</p><ul><li><code>npm init</code> 初始化项目，其实就是创建一个<code>package.json</code>文件。</li><li><code>npm install</code> 安装所有项目依赖。</li><li><code>npm help xxx</code> 查看<code>xxx</code>命令的帮助信息。</li></ul><h5 id="npm-search-搜索-快捷方式-find-s" tabindex="-1"><code>npm search</code> 搜索（快捷方式：<code>find</code>, <code>s</code>） <a class="header-anchor" href="#npm-search-搜索-快捷方式-find-s" aria-label="Permalink to &quot;`npm search` 搜索（快捷方式：`find`, `s`）&quot;">​</a></h5><ul><li><code>xxx</code> 搜索<code>xxx</code> 如：<code>npm search jquery</code>。</li></ul><h5 id="npm-install-安装-快捷方式-i" tabindex="-1"><code>npm install</code> 安装 （快捷方式：<code>i</code>） <a class="header-anchor" href="#npm-install-安装-快捷方式-i" aria-label="Permalink to &quot;`npm install` 安装 （快捷方式：`i`）&quot;">​</a></h5><ul><li><code>xxx</code> 搜索并安装xxx（局部）。安装多个依赖可用空格分割，如<code>npm i jquery bootstrap</code>。</li><li><code>xxx -g</code> 搜索并安装xxx（全局）。安装多个同上。</li><li><code>xxx -D</code> 安装并将依赖信息写在<code>package.json</code>中的<code>devDependencies</code>中。</li><li>快捷方式 <code>i</code>均可，如<code>npm i jquery</code>。</li><li><code>xxx@版本号</code> 指定需要安装的版本号，若不指定将安装最新的稳定版本。</li></ul><h5 id="npm-uninstall-卸载-快捷方式-rm-r" tabindex="-1"><code>npm uninstall</code> 卸载（快捷方式：<code>rm</code>, <code>r</code>） <a class="header-anchor" href="#npm-uninstall-卸载-快捷方式-rm-r" aria-label="Permalink to &quot;`npm uninstall` 卸载（快捷方式：`rm`, `r`）&quot;">​</a></h5><ul><li><code>xxx</code> 卸载xxx。多个依赖可用空格分割。</li><li><code>xxx -D</code> 卸载xxx，并将依赖信息从<code>package.json</code>中的<code>devDependencies</code>中清除。</li></ul><h5 id="npm-list-列出已安装依赖-快捷方式-ls" tabindex="-1"><code>npm list</code> 列出已安装依赖（快捷方式：<code>ls</code>） <a class="header-anchor" href="#npm-list-列出已安装依赖-快捷方式-ls" aria-label="Permalink to &quot;`npm list` 列出已安装依赖（快捷方式：`ls`）&quot;">​</a></h5><ul><li>默认列出局部依赖。</li><li><code>npm list -g</code> 列出已安装的全局依赖。</li></ul><h5 id="npm-outdated-检查过期依赖" tabindex="-1"><code>npm outdated</code> 检查过期依赖 <a class="header-anchor" href="#npm-outdated-检查过期依赖" aria-label="Permalink to &quot;`npm outdated` 检查过期依赖&quot;">​</a></h5><h5 id="npm-update-更新依赖-快捷方式-up" tabindex="-1"><code>npm update</code> 更新依赖（快捷方式：<code>up</code>） <a class="header-anchor" href="#npm-update-更新依赖-快捷方式-up" aria-label="Permalink to &quot;`npm update` 更新依赖（快捷方式：`up`）&quot;">​</a></h5><ul><li><code>xxx</code> 局部更新xxx。</li><li><code>xxx -g</code> 全局更新xxx。</li></ul><h5 id="npm-root-查看依赖安装路径-也就是node-modules的路径" tabindex="-1"><code>npm root</code> 查看依赖安装路径（也就是<code>node_modules</code>的路径） <a class="header-anchor" href="#npm-root-查看依赖安装路径-也就是node-modules的路径" aria-label="Permalink to &quot;`npm root` 查看依赖安装路径（也就是`node_modules`的路径）&quot;">​</a></h5><ul><li>默认查看局部安装路径。</li><li><code>-g</code> 查看全局安装路径。</li></ul><h5 id="npm-view-查看模块的注册信息" tabindex="-1"><code>npm view</code> 查看模块的注册信息 <a class="header-anchor" href="#npm-view-查看模块的注册信息" aria-label="Permalink to &quot;`npm view` 查看模块的注册信息&quot;">​</a></h5><ul><li><code>xxx versions</code> 列出<code>xxx</code>的所有版本， 如：<code>npm view jquery versions</code>。</li><li><code>xxx dependencies</code> 列出<code>xxx</code>的所有依赖， 如：<code>npm view gulp dependencies</code>。</li></ul><h5 id="package-json" tabindex="-1">package.json <a class="header-anchor" href="#package-json" aria-label="Permalink to &quot;package.json&quot;">​</a></h5><p><img src="'+a+'" alt="Pasted image 20250908165423.png"> 生产与开发环境</p><p>好的，这两个符号是 <strong>npm</strong> 的<strong>语义化版本控制（SemVer）</strong> 中非常重要的部分，它们定义了你的项目可以接受依赖包的哪些更新。</p><p>首先，一个版本号通常格式为：<strong><code>主版本号.次版本号.修订号</code></strong> （<code>major.minor.patch</code>），例如 <code>4.18.2</code>。</p><ul><li><strong>主版本号 (Major)</strong>：做了<strong>不兼容的 API 修改</strong>（ Breaking Changes ）。大升级，可能用不了。</li><li><strong>次版本号 (Minor)</strong>：做了<strong>向下兼容的功能性新增</strong>。新功能，但不会破坏老代码。</li><li><strong>修订号 (Patch)</strong>：做了<strong>向下兼容的问题修正</strong>。修 Bug，最安全。</li></ul><p><code>^</code> 和 <code>~</code> 的作用就是用来定义允许自动获取哪个级别的更新。</p><hr><h3 id="_1-插入符号-caret" tabindex="-1">1. 插入符号 (Caret) - <code>^</code> <a class="header-anchor" href="#_1-插入符号-caret" aria-label="Permalink to &quot;1. 插入符号 (Caret) - `^`&quot;">​</a></h3><ul><li><p><strong>含义</strong>：允许接受<strong>不改变版本号中第一个非零数字</strong>的更新。通俗讲，就是允许<strong>次版本号和修订号</strong>的更新，但<strong>不允许主版本号</strong>的更新。</p></li><li><p><strong>规则</strong>：它非常智能，会根据你指定的版本号来灵活判断：</p><ul><li><strong>如果主版本号不是 <code>0</code></strong> (即 <code>&amp;gt;=1.0.0</code>)： <code>^4.18.0</code> → <strong>允许</strong> <code>4.18.1</code>, <code>4.19.0</code>, 但不能是 <code>5.0.0</code>。 （因为第一个非零数字是 <code>4</code>，即主版本号，所以它被锁定，允许 minor 和 patch 更新）。</li><li><strong>如果主版本号是 <code>0</code></strong> (即 <code>0.x.x</code>)，则看次版本号： <code>^0.2.3</code> → <strong>允许</strong> <code>0.2.4</code>, <code>0.2.5</code>, 但不能是 <code>0.3.0</code> 或 <code>1.0.0</code>。 （因为 <code>0</code> 是主版本号，第一个非零数字是 <code>2</code>，即次版本号，所以它被锁定，只允许 patch 更新）。</li><li><strong>如果主版本和次版本都是 <code>0</code></strong>： <code>^0.0.3</code> → <strong>只允许</strong>修订号的更新，即只能是 <code>0.0.3</code> 或 <code>0.0.4</code>，不能是 <code>0.1.0</code>。 （因为第一个非零数字是 <code>3</code>，即修订号）。</li></ul></li><li><p><strong>这是 <code>npm install &amp;lt;package&amp;gt;</code> 的默认行为</strong>，也是最常用的符号。它允许你自动获取安全更新和新功能，同时避免破坏性变更。</p></li></ul><hr><h3 id="_2-波浪符号-tilde" tabindex="-1">2. 波浪符号 (Tilde) - <code>~</code> <a class="header-anchor" href="#_2-波浪符号-tilde" aria-label="Permalink to &quot;2. 波浪符号 (Tilde) - `~`&quot;">​</a></h3><ul><li><p><strong>含义</strong>：允许接受<strong>修订号</strong>的更新，但通常<strong>不允许次版本号</strong>的更新。比 <code>^</code> 更严格。</p></li><li><p><strong>规则</strong>：</p><ul><li><code>~4.18.0</code> → <strong>允许</strong> <code>4.18.1</code>, <code>4.18.2</code>, 但不能是 <code>4.19.0</code>。</li><li><code>~4.18.3</code> → <strong>允许</strong> <code>4.18.4</code>, <code>4.18.5</code>, 但不能是 <code>4.19.0</code>。</li><li>如果指定了次版本号，但修订号省略（被当作 <code>0</code>）： <code>~4.18</code> → 等同于 <code>~4.18.0</code> （允许 <code>4.18.x</code>）</li><li>如果只指定了主版本号： <code>~4</code> → 等同于 <code>~4.0.0</code> （允许 <code>4.0.x</code>，但很奇怪，因为 <code>4</code> 通常会被解析为 <code>^4.0.0</code>）</li></ul></li><li><p><strong>使用场景</strong>：当你希望<strong>只接受错误修复（Bug fixes）</strong>，而对任何新功能都持保守态度时使用。这在追求极度稳定的生产环境中可能有用，但现在更常见的做法是使用 <code>^</code> 并结合 <code>package-lock.json</code> 来锁定。</p></li></ul><hr><h3 id="对比总结与示例" tabindex="-1">对比总结与示例 <a class="header-anchor" href="#对比总结与示例" aria-label="Permalink to &quot;对比总结与示例&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">符号</th><th style="text-align:left;">示例写法</th><th style="text-align:left;">允许的更新范围 (示例)</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>^</code></strong> (Caret)</td><td style="text-align:left;"><code>^4.18.0</code></td><td style="text-align:left;"><code>&amp;gt;=4.18.0</code> <strong>且</strong> <code>&amp;lt;5.0.0</code></td><td style="text-align:left;"><strong>默认推荐</strong>。允许新功能和Bug修复，但禁止大版本更新。</td></tr><tr><td style="text-align:left;"><strong><code>~</code></strong> (Tilde)</td><td style="text-align:left;"><code>~4.18.0</code></td><td style="text-align:left;"><code>&amp;gt;=4.18.0</code> <strong>且</strong> <code>&amp;lt;4.19.0</code></td><td style="text-align:left;">更严格。通常只允许Bug修复。</td></tr><tr><td style="text-align:left;"><strong>(无前缀)</strong></td><td style="text-align:left;"><code>4.18.0</code></td><td style="text-align:left;"><strong>严格等于</strong> <code>4.18.0</code></td><td style="text-align:left;">完全锁定版本，不接受任何更新。</td></tr></tbody></table><h3 id="为什么这些符号需要-package-lock-json" tabindex="-1">为什么这些符号需要 <code>package-lock.json</code>？ <a class="header-anchor" href="#为什么这些符号需要-package-lock-json" aria-label="Permalink to &quot;为什么这些符号需要 `package-lock.json`？&quot;">​</a></h3><p>这正是 <code>package-lock.json</code> 存在的核心原因。</p><p>你的 <code>package.json</code> 里写的是 <code>^4.18.0</code>（一个<strong>范围</strong>），但你需要确保团队和服务器安装的<strong>确切是同一个版本</strong>（比如 <code>4.18.2</code>）。</p><p><code>package-lock.json</code> 的作用就是把这个<strong>灵活的范围</strong> <strong>锁定</strong> 为一个<strong>精确的版本</strong>，记录下你最后一次安装时实际得到的版本 <code>4.18.2</code> 以及它的所有依赖树。这样，无论你什么时候再次安装，得到的都是完全一致的结果，从而保证了依赖环境的绝对一致。</p><p><strong>简单比喻：</strong></p><ul><li><code>package.json</code> (<code>^4.18.0</code>)： “我想要一杯大杯的拿铁。”</li><li><code>package-lock.json</code> (<code>4.18.2</code>)： “这是你2023年10月27日下午3点收到的那杯<strong>具体</strong>的大杯拿铁的所有成分和比例清单（咖啡豆批次、牛奶毫升数、咖啡因含量等）。下次必须严格按照这个清单做。”</li></ul><p>所以，在现代开发中，你应该始终使用 <code>^</code>（享受语义化版本的好处），并<strong>将 <code>package-lock.json</code> 提交到 Git</strong>（享受确定性带来的稳定）。</p>',48)])])}const x=o(n,[["render",l]]);export{m as __pageData,x as default};
